 1→---
 2→/**
 3→ * Mosaic Icon
 4→ *
 5→ * Renders an icon from the mosaic grid system. Each cell contains ONE Significa
 6→ * oval ("egg"). Inactive cells show an xs-sized muted dot. Active cells show
 7→ * a larger egg in currentColor.
 8→ *
 9→ * State transitions driven by parent via CSS custom properties:
10→ *   --mosaic-state: 0 (idle) | 1 (active)
11→ *   --mosaic-duration: transition duration override
12→ *   --mosaic-ease: easing override
13→ */
14→import { mosaicIcons, MOSAIC_SCALES, type MosaicIconName } from "@/lib/mosaic-icons";
15→
16→interface Props {
17→  name: MosaicIconName;
18→  class?: string;
19→}
20→
21→const { name, class: className } = Astro.props;
22→const icon = mosaicIcons[name];
23→
24→const cells = icon.idle.map((idleLevel, i) => {
25→  const hoverLevel = icon.hover?.[i] ?? idleLevel;
26→  return {
27→    idle: MOSAIC_SCALES[idleLevel],
28→    hover: MOSAIC_SCALES[hoverLevel],
29→  };
30→});
31→
32→const EGG_PATH = "M1.73854 1.13073C1.73854 1.61081 1.34935 2 0.86927 2C0.389185 2 0 1.61081 0 1.13073C0 0.650646 0.389185 0 0.86927 0C1.34935 0 1.73854 0.650646 1.73854 1.13073Z";
33→---
34→
35→<span
36→  class:list={["mosaic-icon", className]}
37→  style={`--cols:${icon.cols}`}
38→  aria-hidden="true"
39→>
40→  {cells.map((cell) => (
41→    <span class="mosaic-cell" style={`--i:${cell.idle};--h:${cell.hover}`}>
42→      <svg class="mosaic-egg" viewBox="0 0 1.73854 2">
43→        <path d={EGG_PATH} fill="currentColor" />
44→      </svg>
45→    </span>
46→  ))}
47→</span>
48→
49→<style>
50→  .mosaic-icon {
51→    display: inline-grid;
52→    grid-template-columns: repeat(var(--cols), 1fr);
53→    grid-auto-rows: 1fr;
54→    width: calc(var(--cols) * 2px);
55→    aspect-ratio: 1;
56→    flex-shrink: 0;
57→  }
58→
59→  .mosaic-cell {
60→    position: relative;
61→    aspect-ratio: 1;
62→  }
63→
64→  .mosaic-egg {
65→    position: absolute;
66→    top: 50%;
67→    left: 50%;
68→    transform: translate(-50%, -50%);
69→    display: block;
70→    overflow: visible;
71→
72→    --s: calc(var(--i) + (var(--h) - var(--i)) * var(--mosaic-state, 0));
73→
74→    /* Always render at least xs size so every cell has a visible dot */
75→    --visual-s: max(0.275, var(--s));
76→    width: calc(100% * var(--visual-s));
77→    height: calc(100% * var(--visual-s));
78→
79→    /* 1 when active (s > 0), 0 when background */
80→    --active: clamp(0, var(--s) * 10000, 1);
81→
82→    /* Muted when inactive, full when active */
83→    opacity: calc(0.2 + var(--active) * 0.8);
84→
85→    transition:
86→      width var(--mosaic-duration, var(--duration-fast)) var(--mosaic-ease, var(--ease-out)),
87→      height var(--mosaic-duration, var(--duration-fast)) var(--mosaic-ease, var(--ease-out)),
88→      opacity var(--mosaic-duration, var(--duration-fast)) var(--mosaic-ease, var(--ease-out));
89→  }
90→</style>
91→

