 2→import { cdnUrl, cdnSrcset, DEFAULT_QUALITY } from "@/lib/cdn";
 3→import { contentError } from "@/lib/content-errors";
 4→
 5→interface Props {
 6→  /** Asset path or full URL. Relative paths get the CDN hostname prepended. */
 7→  src: string;
 8→  /** Accessible alt text (required) */
 9→  alt: string;
10→  /** Intrinsic image width in pixels (prevents CLS) */
11→  width: number;
12→  /** Intrinsic image height in pixels (prevents CLS) */
13→  height: number;
14→  /** Optional figure caption */
15→  caption?: string;
16→  /** Set true for above-the-fold / LCP images */
17→  eager?: boolean;
18→  /** Responsive sizes attribute */
19→  sizes?: string;
20→  /** Image quality (0-100) */
21→  quality?: number;
22→}
23→
24→const { src, alt, width, height, caption, eager = false, sizes = "100vw", quality = DEFAULT_QUALITY } = Astro.props;
25→
26→if (!src) contentError("MediaImage", Astro.url.pathname, "Missing required prop: src");
27→if (!alt) contentError("MediaImage", Astro.url.pathname, "Missing required prop: alt");
28→if (!width) contentError("MediaImage", Astro.url.pathname, "Missing required prop: width");
29→if (!height) contentError("MediaImage", Astro.url.pathname, "Missing required prop: height");
30→
31→const imgSrc = cdnUrl(src, { width: 960, quality });
32→const srcset = cdnSrcset(src, { quality });
33→// Only set sizes when we have a srcset
34→const imgSizes = srcset ? sizes : undefined;
35→---
36→
37→{
38→  caption ? (
39→    <figure>
40→      <img
41→        src={imgSrc}
42→        srcset={srcset}
43→        sizes={imgSizes}
44→        alt={alt}
45→        width={width}
46→        height={height}
47→        loading={eager ? "eager" : "lazy"}
48→        fetchpriority={eager ? "high" : "auto"}
49→        decoding={eager ? "sync" : "async"}
50→      />
51→      <figcaption>{caption}</figcaption>
52→    </figure>
53→  ) : (
54→    <img
55→      src={imgSrc}
56→      srcset={srcset}
57→      sizes={imgSizes}
58→      alt={alt}
59→      width={width}
60→      height={height}
61→      loading={eager ? "eager" : "lazy"}
62→      fetchpriority={eager ? "high" : "auto"}
63→      decoding={eager ? "sync" : "async"}
64→    />
65→  )
66→}
