 1→---
 2→import { cdnUrl, DEFAULT_QUALITY } from "@/lib/cdn";
 3→import { contentError } from "@/lib/content-errors";
 4→
 5→interface Props {
 6→  /** Video asset path without CDN hostname */
 7→  src: string;
 8→  /** Optional poster image path (goes through CDN image transforms) */
 9→  poster?: string;
10→  /** Optional figure caption */
11→  caption?: string;
12→  /** Auto-play muted (for showreels) */
13→  autoplay?: boolean;
14→  /** Show playback controls */
15→  controls?: boolean;
16→}
17→
18→const { src, poster, caption, autoplay = false, controls = true } = Astro.props;
19→
20→if (!src) contentError("MediaVideo", Astro.url.pathname, "Missing required prop: src");
21→
22→const videoSrc = cdnUrl(src);
23→const posterSrc = poster ? cdnUrl(poster, { width: 1280, quality: DEFAULT_QUALITY }) : undefined;
24→---
25→
26→{
27→  caption ? (
28→    <figure>
29→      <video
30→        src={videoSrc}
31→        poster={posterSrc}
32→        controls={controls}
33→        autoplay={autoplay}
34→        muted={autoplay}
35→        loop={autoplay}
36→        playsinline={autoplay}
37→        preload={autoplay ? "auto" : "metadata"}
38→      >
39→        <p>Your browser does not support the video element.</p>
40→      </video>
41→      <figcaption>{caption}</figcaption>
42→    </figure>
43→  ) : (
44→    <video
45→      src={videoSrc}
46→      poster={posterSrc}
47→      controls={controls}
48→      autoplay={autoplay}
49→      muted={autoplay}
50→      loop={autoplay}
51→      playsinline={autoplay}
52→      preload={autoplay ? "auto" : "metadata"}
53→    >
54→      <p>Your browser does not support the video element.</p>
55→    </video>
56→  )
57→}
