 2→import { contentError } from "@/lib/content-errors";
 3→
 4→interface MetricItem {
 5→  value: string;
 6→  label: string;
 7→}
 8→
 9→interface Props {
10→  items: MetricItem[];
11→}
12→
13→const { items } = Astro.props;
14→
15→if (!items || items.length === 0) {
16→  contentError("Metrics", Astro.url.pathname, "Metrics requires at least one item");
17→}
18→---
19→
20→<dl class="metrics">
21→  {
22→    items.map((item) => (
23→      <div class="metric">
24→        <dt>{item.label}</dt>
25→        <dd>{item.value}</dd>
26→      </div>
27→    ))
28→  }
29→</dl>
30→
31→<style>
32→  .metrics {
33→    display: grid;
34→    grid-template-columns: repeat(auto-fit, minmax(10rem, 1fr));
35→    gap: 1.5rem;
36→  }
37→
38→  .metric dt {
39→    font-size: var(--text-sm);
40→    color: var(--color-text-muted);
41→  }
42→
43→  .metric dd {
44→    font-size: var(--text-2xl);
45→    font-weight: var(--weight-bold);
46→    line-height: var(--leading-tight);
47→  }
48→</style>
