  2→import { getEntry } from "astro:content";
  3→import { cdnUrl, DEFAULT_QUALITY } from "@/lib/cdn";
  4→import { contentError } from "@/lib/content-errors";
  5→
  6→interface Props {
  7→  project: string;
  8→  title?: string;
  9→  description?: string;
 10→}
 11→
 12→const { project: slug, title, description } = Astro.props;
 13→
 14→if (!slug) {
 15→  contentError("ProjectCrossSell", Astro.url.pathname, "Missing required prop: project");
 16→}
 17→
 18→const project = await getEntry("projects", slug);
 19→
 20→if (!project) {
 21→  contentError(
 22→    "ProjectCrossSell",
 23→    Astro.url.pathname,
 24→    `Project "${slug}" not found. Check the slug exists in src/content/projects/.`
 25→  );
 26→}
 27→
 28→const thumbnailSrc = cdnUrl(project.data.thumbnail, {
 29→  width: 640,
 30→  quality: DEFAULT_QUALITY,
 31→});
 32→---
 33→
 34→<aside class="cross-sell">
 35→  <a href={`/projects/${project.id}`} class="cross-sell-link">
 36→    {
 37→      project.data.thumbnail && (
 38→        <img src={thumbnailSrc} alt={project.data.title} loading="lazy" decoding="async" class="cross-sell-image" />
 39→      )
 40→    }
 41→    <div class="cross-sell-content">
 42→      {title && <span class="cross-sell-label">{title}</span>}
 43→      <span class="cross-sell-title">{project.data.title}</span>
 44→      {(description || project.data.tagline) && <span class="cross-sell-tagline">{description || project.data.tagline}</span>}
 45→      <span class="cross-sell-cta">View case study →</span>
 46→    </div>
 47→  </a>
 48→</aside>
 49→
 50→<style>
 51→  .cross-sell {
 52→    margin: 3rem 0;
 53→    padding: 2rem;
 54→    background: var(--color-surface-alt);
 55→    border: 1px solid var(--color-border);
 56→    border-radius: 0.5rem;
 57→  }
 58→
 59→  .cross-sell-link {
 60→    display: flex;
 61→    gap: 2rem;
 62→    align-items: center;
 63→    text-decoration: none;
 64→    color: var(--color-text);
 65→    transition: opacity var(--duration-fast) var(--ease-out);
 66→  }
 67→
 68→  .cross-sell-link:hover {
 69→    opacity: 0.8;
 70→  }
 71→
 72→  .cross-sell-image {
 73→    flex-shrink: 0;
 74→    width: 200px;
 75→    height: auto;
 76→    border-radius: 0.25rem;
 77→    object-fit: cover;
 78→  }
 79→
 80→  .cross-sell-content {
 81→    display: flex;
 82→    flex-direction: column;
 83→    gap: 0.5rem;
 84→  }
 85→
 86→  .cross-sell-label {
 87→    font-size: var(--text-xs);
 88→    font-weight: var(--weight-semibold);
 89→    text-transform: uppercase;
 90→    letter-spacing: 0.05em;
 91→    color: var(--color-text-muted);
 92→  }
 93→
 94→  .cross-sell-title {
 95→    font-size: var(--text-xl);
 96→    font-weight: var(--weight-bold);
 97→    line-height: var(--leading-tight);
 98→  }
 99→
100→  .cross-sell-tagline {
101→    font-size: var(--text-base);
102→    line-height: var(--leading-normal);
103→    color: var(--color-text-muted);
104→  }
105→
