 1→/**
 2→ * CDN configuration and URL helpers.
 3→ *
 4→ * All media is served through our self-hosted image transform service
 5→ * at cdn.significa.co (Cloudflare → Fly.io → S3), with on-the-fly
 6→ * sharp-based image transforms via URL query parameters.
 7→ */
 8→
 9→const CDN_HOSTNAME = "https://cdn.significa.co";
10→
11→/** Default responsive breakpoints for srcset generation */
12→const SRCSET_WIDTHS = [640, 960, 1280, 1920];
13→
14→/** Default image quality */
15→const DEFAULT_QUALITY = 80;
16→
17→interface CdnImageOptions {
18→  width?: number;
19→  quality?: number;
20→  format?: "webp" | "avif" | "jpeg" | "png";
21→}
22→
23→/**
24→ * Check whether a src is already an absolute URL (external or full CDN link).
25→ */
26→function isAbsoluteUrl(src: string): boolean {
27→  return src.startsWith("http://") || src.startsWith("https://");
28→}
29→
30→/**
31→ * Build a full CDN URL with optional image transform parameters.
32→ *
33→ * If `src` is already an absolute URL it's used as-is (no hostname prepended).
34→ * Transform query params are still appended when the URL points to our CDN.
35→ */
36→export function cdnUrl(src: string, options: CdnImageOptions = {}): string {
37→  const params = new URLSearchParams();
38→
39→  if (options.width) params.set("width", String(options.width));
40→  if (options.quality) params.set("quality", String(options.quality));
41→  if (options.format) params.set("format", options.format);
42→
43→  const query = params.toString();
44→
45→  // Already a full URL — return as-is (with params only for our own CDN)
46→  if (isAbsoluteUrl(src)) {
47→    if (!query) return src;
48→    if (src.startsWith(CDN_HOSTNAME)) {
49→      const separator = src.includes("?") ? "&" : "?";
50→      return `${src}${separator}${query}`;
51→    }
52→    return src;
53→  }
54→
55→  // Relative path — prepend CDN hostname
56→  const normalizedPath = src.startsWith("/") ? src : `/${src}`;
57→  return `${CDN_HOSTNAME}${normalizedPath}${query ? `?${query}` : ""}`;
58→}
59→
60→/**
61→ * Generate a srcset string for responsive images.
62→ *
63→ * Returns `undefined` for external URLs that aren't on our CDN,
64→ * since we can't generate width variants for those.
65→ */
66→export function cdnSrcset(src: string, options: { quality?: number; widths?: number[] } = {}): string | undefined {
67→  // External URL not on our CDN — no srcset possible
68→  if (isAbsoluteUrl(src) && !src.startsWith(CDN_HOSTNAME)) {
69→    return undefined;
70→  }
71→
72→  const quality = options.quality ?? DEFAULT_QUALITY;
73→  const widths = options.widths ?? SRCSET_WIDTHS;
74→
75→  return widths.map((w) => `${cdnUrl(src, { width: w, quality })} ${w}w`).join(", ");
