  2→import BaseLayout from "@/layouts/base.astro";
  3→import { getProjects } from "@/lib/collections";
  4→import { getCollection } from "astro:content";
  5→import { cdnUrl } from "@/lib/cdn";
  6→
  7→const projects = await getProjects();
  8→const allAwards = await getCollection("awards");
  9→
 10→// Group awards by project
 11→const awardsByProject = new Map<string, Array<{ award: string; year: number; url?: string }>>();
 12→for (const award of allAwards) {
 13→  const projectId = award.data.project.id;
 14→  if (!awardsByProject.has(projectId)) {
 15→    awardsByProject.set(projectId, []);
 16→  }
 17→  awardsByProject.get(projectId)!.push({
 18→    award: award.data.award,
 19→    year: award.data.year,
 20→    url: award.data.url,
 21→  });
 22→}
 23→
 24→// Extract unique industries and deliverables
 25→const industries = Array.from(new Set(projects.flatMap((p) => p.data.industry || []))).sort();
 26→const deliverables = Array.from(new Set(projects.flatMap((p) => p.data.deliverable || []))).sort();
 27→
 28→// Format label for display: "mobile-app" → "Mobile App"
 29→function formatLabel(value: string): string {
 30→  return value
 31→    .split("-")
 32→    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
 33→    .join(" ");
 34→}
 35→---
 36→
 37→<BaseLayout title="Projects — Significa" description="Selected work from Significa's portfolio.">
 38→  <div class="page">
 39→    <header class="page-header">
 40→      <h1>Projects.</h1>
 41→    </header>
 42→
 43→    <section class="filters" aria-label="Project filters">
 44→      <details id="filter-panel">
 45→        <summary class="filter-toggle">
 46→          <span>Filters</span>
 47→          <span class="filter-count" data-filter-count hidden>0</span>
 48→          <svg
 49→            class="chevron"
 50→            width="16"
 51→            height="16"
 52→            viewBox="0 0 16 16"
 53→            fill="none"
 54→            xmlns="http://www.w3.org/2000/svg"
 55→            aria-hidden="true"
 56→          >
 57→            <path d="M4 6L8 10L12 6" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"
 58→            ></path>
 59→          </svg>
 60→        </summary>
 61→
 62→        <div class="filter-panel-content">
 63→          <div class="filter-header">
 64→            <h3>Filter projects</h3>
 65→            <button class="clear-button" type="button" data-clear-filters hidden>Clear all</button>
 66→          </div>
 67→
 68→          {
 69→            industries.length > 0 && (
 70→              <fieldset class="filter-group">
 71→                <legend>Industry</legend>
 72→                <div class="filter-options">
 73→                  {industries.map((industry) => (
 74→                    <label class="filter-option">
 75→                      <input type="checkbox" name="industry" value={industry} />
 76→                      <span class="checkbox-custom" />
 77→                      <span class="filter-label">{formatLabel(industry)}</span>
 78→                    </label>
 79→                  ))}
 80→                </div>
 81→              </fieldset>
 82→            )
 83→          }
 84→
 85→          {
 86→            deliverables.length > 0 && (
 87→              <fieldset class="filter-group">
 88→                <legend>Deliverable</legend>
 89→                <div class="filter-options">
 90→                  {deliverables.map((deliverable) => (
 91→                    <label class="filter-option">
 92→                      <input type="checkbox" name="deliverable" value={deliverable} />
 93→                      <span class="checkbox-custom" />
 94→                      <span class="filter-label">{formatLabel(deliverable)}</span>
 95→                    </label>
 96→                  ))}
 97→                </div>
 98→              </fieldset>
 99→            )
100→          }
101→        </div>
102→      </details>
103→
104→      <p class="results-count" data-results-count>
105→        Showing {projects.length} of {projects.length} projects
106→      </p>
107→    </section>
108→
109→    <div class="projects-grid" data-projects-grid>
110→      {
111→        projects.map((project) => {
112→          const projectAwards = awardsByProject.get(project.id) || [];
113→          const thumbnailUrl = project.data.thumbnail ? cdnUrl(project.data.thumbnail, { width: 800, quality: 85 }) : null;
114→
115→          return (
116→            <article
117→              class="project-card"
118→              data-industries={(project.data.industry || []).join(",")}
119→              data-deliverables={(project.data.deliverable || []).join(",")}
120→            >
121→              <a href={`/projects/${project.id}`} class="project-link">
122→                {thumbnailUrl && (
123→                  <div class="project-thumbnail">
124→                    <img src={thumbnailUrl} alt={project.data.title} loading="lazy" decoding="async" />
125→                  </div>
126→                )}
127→
128→                <div class="project-info">
129→                  <h2 class="project-title">{project.data.title}</h2>
130→                  {project.data.tagline && <p class="project-tagline">{project.data.tagline}</p>}
131→
132→                  {projectAwards.length > 0 && (
133→                    <ul class="awards-list" role="list">
134→                      {projectAwards.slice(0, 5).map((award) => (
135→                        <li class="award-badge">
136→                          <span class="award-name">{award.award}</span>
137→                        </li>
138→                      ))}
139→                    </ul>
140→                  )}
141→
142→                  <span class="view-project">View project →</span>
143→                </div>
144→              </a>
145→            </article>
146→          );
147→        })
148→      }
149→    </div>
150→
151→    <div class="no-results" data-no-results hidden>
152→      <p>No projects match the selected filters.</p>
153→      <button class="clear-button-large" type="button" data-clear-filters>Clear filters</button>
154→    </div>
155→  </div>
156→</BaseLayout>
