158→<script>
159→  function initFilters() {
160→    const cards = document.querySelectorAll<HTMLElement>("[data-projects-grid] .project-card");
161→    const checkboxes = document.querySelectorAll<HTMLInputElement>(".filter-option input[type='checkbox']");
162→    const countEl = document.querySelector<HTMLElement>("[data-filter-count]");
163→    const resultsEl = document.querySelector<HTMLElement>("[data-results-count]");
164→    const noResultsEl = document.querySelector<HTMLElement>("[data-no-results]");
165→    const clearButtons = document.querySelectorAll<HTMLButtonElement>("[data-clear-filters]");
166→    const total = cards.length;
167→
168→    function getSelectedValues(name: string): Set<string> {
169→      const values = new Set<string>();
170→      checkboxes.forEach((cb) => {
171→        if (cb.name === name && cb.checked) values.add(cb.value);
172→      });
173→      return values;
174→    }
175→
176→    function applyFilters() {
177→      const selectedIndustries = getSelectedValues("industry");
178→      const selectedDeliverables = getSelectedValues("deliverable");
179→      const activeCount = selectedIndustries.size + selectedDeliverables.size;
180→
181→      // Update URL without reload
182→      const params = new URLSearchParams();
183→      selectedIndustries.forEach((v) => params.append("industry", v));
184→      selectedDeliverables.forEach((v) => params.append("deliverable", v));
185→      const qs = params.toString();
186→      const url = qs ? `${window.location.pathname}?${qs}` : window.location.pathname;
187→      history.replaceState(null, "", url);
188→
189→      // Show/hide filter count badge
190→      if (countEl) {
191→        countEl.textContent = String(activeCount);
192→        countEl.hidden = activeCount === 0;
193→      }
194→
195→      // Show/hide clear buttons
196→      clearButtons.forEach((btn) => {
197→        btn.hidden = activeCount === 0;
198→      });
199→
200→      // Filter cards
201→      let visible = 0;
202→      cards.forEach((card) => {
203→        const cardIndustries = (card.dataset.industries || "").split(",").filter(Boolean);
204→        const cardDeliverables = (card.dataset.deliverables || "").split(",").filter(Boolean);
205→
206→        const matchesIndustry = selectedIndustries.size === 0 || cardIndustries.some((i) => selectedIndustries.has(i));
207→        const matchesDeliverable = selectedDeliverables.size === 0 || cardDeliverables.some((d) => selectedDeliverables.has(d));
208→
209→        const show = matchesIndustry && matchesDeliverable;
210→        card.hidden = !show;
211→        if (show) visible++;
212→      });
213→
214→      // Update results count
215→      if (resultsEl) {
216→        resultsEl.textContent = `Showing ${visible} of ${total} projects`;
217→      }
218→
219→      // No results message
220→      if (noResultsEl) {
221→        noResultsEl.hidden = visible > 0;
222→      }
223→    }
224→
225→    function syncFromUrl() {
226→      const params = new URLSearchParams(window.location.search);
227→      const industries = new Set(params.getAll("industry"));
228→      const deliverableParams = new Set(params.getAll("deliverable"));
229→
230→      checkboxes.forEach((cb) => {
231→        const values = cb.name === "industry" ? industries : deliverableParams;
232→        cb.checked = values.has(cb.value);
233→      });
234→
235→      // Auto-open panel if filters are active
236→      if (industries.size > 0 || deliverableParams.size > 0) {
237→        const details = document.getElementById("filter-panel") as HTMLDetailsElement | null;
238→        if (details) details.open = true;
239→      }
240→
241→      applyFilters();
242→    }
243→
244→    function clearAll() {
245→      checkboxes.forEach((cb) => (cb.checked = false));
246→      applyFilters();
247→    }
248→
249→    // Event listeners
250→    checkboxes.forEach((cb) => cb.addEventListener("change", applyFilters));
251→    clearButtons.forEach((btn) => btn.addEventListener("click", clearAll));
252→    window.addEventListener("popstate", syncFromUrl);
253→
254→    // Initialize from URL on load
255→    syncFromUrl();
256→  }
257→
258→  // Run on initial load and after view transitions
259→  document.addEventListener("astro:page-load", initFilters);
260→</script>
