  4→import { cdnUrl } from "@/lib/cdn";
  5→
  6→const allPosts = await getPosts();
  7→
  8→// Separate featured post (most recent)
  9→const featuredPost = allPosts[0];
 10→const recentPosts = allPosts.slice(1);
 11→
 12→// Extract all unique tags from posts
 13→const allTags = [...new Set(allPosts.flatMap((post) => post.data.tags || []))].sort();
 14→
 15→// Calculate reading time helper
 16→function calculateReadingTime(post: (typeof allPosts)[number]): number {
 17→  const wordCount = post.body?.split(/\s+/).length ?? 0;
 18→  return wordCount > 0 ? Math.ceil(wordCount / 200) : 5;
 19→}
 20→
 21→// Format date helper
 22→function formatDate(date: Date): string {
 23→  return date.toLocaleDateString("en-US", {
 24→    year: "numeric",
 25→    month: "long",
 26→    day: "numeric",
 27→  });
 28→}
