167→<!-- Tag filtering script -->
168→<script>
169→  function initTagFilter() {
170→    const buttons = document.querySelectorAll<HTMLButtonElement>(".tag-button");
171→    const cards = document.querySelectorAll<HTMLElement>(".blog-card");
172→
173→    if (!buttons.length || !cards.length) return;
174→
175→    buttons.forEach((button) => {
176→      button.addEventListener("click", () => {
177→        const selectedTag = button.dataset.tag;
178→        if (!selectedTag) return;
179→
180→        // Update active state
181→        buttons.forEach((btn) => btn.classList.remove("active"));
182→        button.classList.add("active");
183→
184→        // Filter cards
185→        cards.forEach((card) => {
186→          const cardTagsStr = card.dataset.tags;
187→          if (!cardTagsStr) return;
188→
189→          try {
190→            const cardTags = JSON.parse(cardTagsStr) as string[];
191→
192→            if (selectedTag === "all" || cardTags.includes(selectedTag)) {
193→              card.style.display = "";
194→              // Animate in
195→              card.style.animation = "fadeIn 0.3s ease-out";
196→            } else {
197→              card.style.display = "none";
198→            }
199→          } catch (e) {
200→            console.error("Error parsing tags:", e);
201→          }
202→        });
203→      });
204→    });
205→  }
206→
207→  // Run on initial load and after View Transition navigation
208→  initTagFilter();
209→  document.addEventListener("astro:after-swap", initTagFilter);
210→</script>
