  7→---
  8→
  9→<BaseLayout
 10→  title="Work with us"
 11→  description="Let's build something meaningful together. Get in touch to start a conversation about your next digital product."
 12→>
 13→  <!-- Intro -->
 14→  <section class="intro">
 15→    <div class="intro-inner">
 16→      <h1>
 17→        <span class="intro-muted">We partner with companies that care about craft.</span>
 18→        {" "}
 19→        Let's build something meaningful together.
 20→      </h1>
 21→    </div>
 22→  </section>
 23→
 24→  <!-- Contact -->
 25→  <section class="contact">
 26→    <div class="contact-inner">
 27→      <div class="contact-card">
 28→        <h2>Get in touch</h2>
 29→        <p>Drop us a line and tell us about your project. We'll get back to you within two business days.</p>
 30→        <a href="mailto:hello@significa.co" class="contact-email"> hello@significa.co </a>
 31→      </div>
 32→      <div class="contact-details">
 33→        <div class="contact-detail">
 34→          <h3>Based in</h3>
 35→          <p>Porto, Portugal</p>
 36→        </div>
 37→        <div class="contact-detail">
 38→          <h3>Working hours</h3>
 39→          <p>Mon–Fri, 9am–6pm WET</p>
 40→        </div>
 41→        <div class="contact-detail">
 42→          <h3>Working with</h3>
 43→          <p>Teams worldwide, remotely and on-site</p>
 44→        </div>
 45→      </div>
 46→    </div>
 47→  </section>
 48→
 49→  <!-- Process -->
 50→  <section class="process">
 51→    <div class="process-inner">
 52→      <h2 class="section-heading">How we work together</h2>
 53→      <ol class="process-steps">
 54→        <li class="process-step">
 55→          <span class="step-number">01</span>
 56→          <h3>Conversation</h3>
 57→          <p>
 58→            We start by listening. Tell us about your business, your users, and what you're trying to achieve. No commitments,
 59→            no pitches — just an honest conversation about whether we're the right fit.
 60→          </p>
 61→        </li>
 62→        <li class="process-step">
 63→          <span class="step-number">02</span>
 64→          <h3>Proposal</h3>
 65→          <p>
 66→            If there's a fit, we scope the work together. You get a clear proposal with timeline, deliverables, and pricing. No
 67→            surprises, no hidden costs.
 68→          </p>
 69→        </li>
 70→        <li class="process-step">
 71→          <span class="step-number">03</span>
 72→          <h3>Kick-off</h3>
 73→          <p>
 74→            A small, dedicated team gets assigned to your project. We set up communication channels, align on goals, and hit the
 75→            ground running.
 76→          </p>
 77→        </li>
 78→        <li class="process-step">
 79→          <span class="step-number">04</span>
 80→          <h3>Build</h3>
 81→          <p>
 82→            Design and engineering work in tight loops. You see progress weekly, give feedback early, and stay involved
 83→            throughout. No big reveals — just steady, visible progress.
 84→          </p>
 85→        </li>
 86→        <li class="process-step">
 87→          <span class="step-number">05</span>
 88→          <h3>Launch & iterate</h3>
 89→          <p>
 90→            We ship, measure, and improve. The work doesn't end at launch — we stick around to make sure what we built actually
 91→            works in the real world.
 92→          </p>
 93→        </li>
 94→      </ol>
 95→    </div>
 96→  </section>
 97→
 98→  <!-- What we look for -->
 99→  <section class="criteria">
100→    <div class="criteria-inner">
101→      <div class="criteria-text">
102→        <h2>Projects we're a good fit for</h2>
103→        <p>
104→          We're selective about the work we take on. Not because we're precious about it, but because focus produces better
105→          outcomes for everyone.
106→        </p>
107→      </div>
108→      <ul class="criteria-list">
109→        <li>
110→          <strong>Digital products</strong> — apps, platforms, and tools that solve real problems for real users.
111→        </li>
112→        <li>
113→          <strong>E-commerce</strong> — online stores and platforms where design directly impacts revenue.
114→        </li>
115→        <li>
116→          <strong>Design systems</strong> — scalable component libraries and design foundations that grow with your team.
117→        </li>
118→        <li>
119→          <strong>Websites</strong> — marketing sites, corporate sites, and web experiences where craft matters.
120→        </li>
121→      </ul>
122→    </div>
123→  </section>
124→
125→  <!-- Testimonials -->
126→  {
127→    testimonials.length > 0 && (
128→      <section class="testimonials">
129→        <div class="testimonials-inner">
130→          <h2 class="section-heading">What our clients say</h2>
131→          <div class="testimonials-grid">
132→            {testimonials.map((t) => (
133→              <blockquote class="testimonial-card">
134→                <p class="testimonial-quote">{t.data.quote}</p>
135→                <footer class="testimonial-author">
136→                  <cite>
137→                    <strong>{t.data.author}</strong>
138→                    <span>
139→                      {t.data.role} at {t.data.company}
140→                    </span>
141→                  </cite>
142→                </footer>
143→              </blockquote>
144→            ))}
145→          </div>
146→        </div>
147→      </section>
148→    )
149→  }
150→
151→  <!-- Clients -->
152→  {
153→    clients.length > 0 && (
154→      <section class="clients">
155→        <div class="clients-inner">
156→          <h2 class="section-heading">Companies we've worked with</h2>
157→          <ul>
158→            {clients.map((client) => (
159→              <li>
160→                {client.data.url ? (
161→                  <a href={client.data.url} target="_blank" rel="noopener noreferrer" title={client.data.name}>
162→                    <span class="client-name">{client.data.name}</span>
163→                  </a>
164→                ) : (
165→                  <span class="client-name">{client.data.name}</span>
166→                )}
167→              </li>
168→            ))}
169→          </ul>
170→        </div>
171→      </section>
172→    )
173→  }
