  1→---
  2→import { getEntry, render } from "astro:content";
  3→import BaseLayout from "@/layouts/base.astro";
  4→import { mdxComponents } from "@/components/mdx/components";
  5→import { articleJsonLd } from "@/lib/seo";
  6→import { getPosts } from "@/lib/collections";
  7→import { cdnUrl } from "@/lib/cdn";
  8→
  9→export async function getStaticPaths() {
 10→  const posts = await getPosts();
 11→  return posts.map((post) => ({
 12→    params: { slug: post.id },
 13→    props: { post },
 14→  }));
 15→}
 16→
 17→const { post } = Astro.props;
 18→const { Content } = await render(post);
 19→
 20→const seo = post.data.seo;
 21→const title = seo?.metaTitle ?? post.data.title;
 22→const description = seo?.metaDescription ?? post.data.description ?? `${post.data.title} — Significa Blog`;
 23→
 24→const relatedProjects = post.data.relatedProjects?.length
 25→  ? await Promise.all(post.data.relatedProjects.map((ref) => getEntry(ref)))
 26→  : [];
 27→
 28→// Calculate reading time (rough estimate: 200 words per minute)
 29→const wordCount = post.body?.split(/\s+/).length ?? 0;
 30→const readingTime = wordCount > 0 ? Math.ceil(wordCount / 200) : 5;
 31→
 32→// Format date
 33→const formattedDate = post.data.date.toLocaleDateString("en-US", {
 34→  year: "numeric",
 35→  month: "long",
 36→  day: "numeric",
 37→});
 38→---
 39→
 40→<BaseLayout title={title} description={description} ogImage={seo?.ogImage} type="article" publishedAt={post.data.date}>
 41→  <article class="blog-post">
 42→    <header class="blog-header">
 43→      <div class="blog-header-inner">
 44→        <div class="blog-meta">
 45→          <time datetime={post.data.date.toISOString()}>{formattedDate}</time>
 46→          <span class="meta-separator">•</span>
 47→          <span class="reading-time">{readingTime} min read</span>
 48→        </div>
 49→        <h1 class="blog-title">{post.data.title}</h1>
 50→        {post.data.description && <p class="blog-description">{post.data.description}</p>}
 51→        {
 52→          post.data.tags && post.data.tags.length > 0 && (
 53→            <ul class="blog-tags">
 54→              {post.data.tags.map((tag) => (
 55→                <li class="blog-tag">{tag}</li>
 56→              ))}
 57→            </ul>
 58→          )
 59→        }
 60→      </div>
 61→    </header>
 62→
 63→    {
 64→      post.data.thumbnail && (
 65→        <div class="blog-hero">
 66→          <img
 67→            src={cdnUrl(post.data.thumbnail, { width: 1600, quality: 85 })}
 68→            alt={post.data.title}
 69→            width="1600"
 70→            height="900"
 71→            loading="eager"
 72→            decoding="async"
 73→          />
 74→        </div>
 75→      )
 76→    }
 77→
 78→    <div class="blog-content">
 79→      <div class="blog-content-inner">
 80→        <Content components={mdxComponents} />
 81→      </div>
 82→    </div>
 83→
 84→    {
 85→      post.data.author && (
 86→        <footer class="blog-footer">
 87→          <div class="blog-footer-inner">
 88→            <div class="author-card">
 89→              <div class="author-info">
 90→                <strong class="author-name">{post.data.author}</strong>
 91→                <span class="author-role">Author</span>
 92→              </div>
 93→            </div>
 94→          </div>
 95→        </footer>
 96→      )
 97→    }
 98→
 99→    {
100→      relatedProjects.length > 0 && (
101→        <aside class="related-projects">
102→          <div class="related-projects-inner">
103→            <h2 class="related-title">Related Work</h2>
104→            <ul class="related-list">
105→              {relatedProjects.map(
106→                (project) =>
107→                  project && (
108→                    <li class="related-item">
109→                      <a href={`/projects/${project.id}`} class="related-link">
110→                        {project.data.thumbnail && (
111→                          <div class="related-image">
112→                            <img
113→                              src={cdnUrl(project.data.thumbnail, { width: 600, quality: 80 })}
114→                              alt={project.data.title}
115→                              width="600"
116→                              height="400"
117→                              loading="lazy"
118→                              decoding="async"
119→                            />
120→                          </div>
121→                        )}
122→                        <div class="related-content">
123→                          <h3 class="related-project-title">{project.data.title}</h3>
124→                          {project.data.tagline && <p class="related-tagline">{project.data.tagline}</p>}
125→                        </div>
126→                      </a>
127→                    </li>
128→                  )
129→              )}
130→            </ul>
131→          </div>
132→        </aside>
133→      )
134→    }
135→
136→    <div class="blog-cta">
137→      <div class="blog-cta-inner">
138→        <h2>We build and launch functional digital products.</h2>
139→        <a href="/work-with-us" class="cta-button">Get a quote</a>
140→      </div>
141→    </div>
142→  </article>
143→
144→  <script
145→    is:inline
146→    type="application/ld+json"
147→    set:html={JSON.stringify(
148→      articleJsonLd({
149→        title: post.data.title,
150→        description,
151→        url: new URL(`/blog/${post.id}`, Astro.site).href,
152→        publishedAt: post.data.date,
153→        author: post.data.author,
154→        image: seo?.ogImage || post.data.thumbnail,
155→      })
156→    )}
157→  />
158→</BaseLayout>
