 1→---
 2→import { getEntry, render } from "astro:content";
 3→import BaseLayout from "@/layouts/base.astro";
 4→import { mdxComponents } from "@/components/mdx/components";
 5→import { getProjects } from "@/lib/collections";
 6→
 7→export async function getStaticPaths() {
 8→  const projects = await getProjects();
 9→  return projects.map((project) => ({
10→    params: { slug: project.id },
11→    props: { project },
12→  }));
13→}
14→
15→const { project } = Astro.props;
16→const { Content } = await render(project);
17→
18→const seo = project.data.seo;
19→const title = seo?.metaTitle ?? project.data.title;
20→const description = seo?.metaDescription ?? project.data.tagline ?? `${project.data.title} — Significa`;
21→
22→const relatedProjects = project.data.relatedProjects?.length
23→  ? await Promise.all(project.data.relatedProjects.map((ref) => getEntry(ref)))
24→  : [];
25→---
26→
27→<BaseLayout title={title} description={description} ogImage={seo?.ogImage}>
28→  <article>
29→    <header>
30→      <h1>{project.data.title}</h1>
31→      {project.data.tagline && <p>{project.data.tagline}</p>}
32→      {project.data.client && <p>Client: {project.data.client}</p>}
33→    </header>
34→    <Content components={mdxComponents} />
35→    {
36→      relatedProjects.length > 0 && (
37→        <aside>
38→          <h2>Related Projects</h2>
39→          <ul>
40→            {relatedProjects.map(
41→              (related) =>
42→                related && (
43→                  <li>
44→                    <a href={`/projects/${related.id}`}>{related.data.title}</a>
45→                  </li>
46→                )
47→            )}
48→          </ul>
49→        </aside>
50→      )
51→    }
52→  </article>
53→</BaseLayout>
