  1→---
  2→import { getCollection, render } from "astro:content";
  3→import BaseLayout from "@/layouts/base.astro";
  4→import { mdxComponents } from "@/components/mdx/components";
  5→import { getHandbookIndex, getHandbookBreadcrumbs, getHandbookChildren } from "@/lib/collections";
  6→import { cdnUrl, cdnSrcset, DEFAULT_QUALITY } from "@/lib/cdn";
  7→
  8→export async function getStaticPaths() {
  9→  const pages = await getCollection("handbook");
 10→  return pages.map((page) => ({
 11→    params: { slug: page.id },
 12→    props: { page },
 13→  }));
 14→}
 15→
 16→const { page } = Astro.props;
 17→const { Content } = await render(page);
 18→
 19→const seo = page.data.seo;
 20→const title = seo?.metaTitle ?? `${page.data.title} — Significa Handbook`;
 21→const description = seo?.metaDescription ?? page.data.description ?? `${page.data.title} — Significa Handbook`;
 22→
 23→const [breadcrumbs, children, indexGroups] = await Promise.all([
 24→  getHandbookBreadcrumbs(page),
 25→  getHandbookChildren(page.id),
 26→  getHandbookIndex(),
 27→]);
 28→
 29→// Determine if this is a top-level page or a child
 30→const isChild = page.id.includes("/");
 31→const parentId = isChild ? page.id.split("/").slice(0, -1).join("/") : null;
 32→
 33→function formatDate(date: Date) {
 34→  return date.toLocaleDateString("en-US", {
 35→    year: "numeric",
 36→    month: "long",
 37→    day: "numeric",
 38→  });
 39→}
 40→---
 41→
 42→<BaseLayout title={title} description={description} ogImage={seo?.ogImage}>
 43→  <div class="layout">
 44→    <!-- Sidebar -->
 45→    <nav class="sidebar" aria-label="Handbook navigation">
 46→      <a href="/handbook" class="handbook-home"> ← Handbook </a>
 47→
 48→      <div class="nav-groups">
 49→        {
 50→          indexGroups.map(({ group, pages }) =>
 51→            pages.length > 0 ? (
 52→              <div class="nav-group">
 53→                <p class="nav-group-title">{group.data.title}</p>
 54→                <ul role="list" class="nav-list">
 55→                  {pages.map(({ page: navPage, children: navChildren }) => {
 56→                    const isActivePage = navPage.id === page.id;
 57→                    const isActiveParent = parentId === navPage.id;
 58→                    const isExpanded = isActivePage || isActiveParent;
 59→
 60→                    return (
 61→                      <li>
 62→                        <a
 63→                          href={`/handbook/${navPage.id}`}
 64→                          class:list={["nav-link", { active: isActivePage }]}
 65→                          aria-current={isActivePage ? "page" : undefined}
 66→                        >
 67→                          {navPage.data.title}
 68→                        </a>
 69→                        {navChildren.length > 0 && isExpanded && (
 70→                          <ul role="list" class="nav-children">
 71→                            {navChildren.map((child) => {
 72→                              const isActiveChild = child.id === page.id;
 73→                              return (
 74→                                <li>
 75→                                  <a
 76→                                    href={`/handbook/${child.id}`}
 77→                                    class:list={["nav-child-link", { active: isActiveChild }]}
 78→                                    aria-current={isActiveChild ? "page" : undefined}
 79→                                  >
 80→                                    {child.data.title}
 81→                                  </a>
 82→                                </li>
 83→                              );
 84→                            })}
 85→                          </ul>
 86→                        )}
 87→                      </li>
 88→                    );
 89→                  })}
 90→                </ul>
 91→              </div>
 92→            ) : null
 93→          )
 94→        }
 95→      </div>
 96→    </nav>
 97→
 98→    <!-- Main content -->
 99→    <div class="content-wrapper">
100→      <article class="content">
101→        <!-- Breadcrumbs (only for child pages) -->
102→        {
103→          breadcrumbs.length > 0 && (
104→            <nav class="breadcrumbs" aria-label="Breadcrumb">
105→              <ol role="list">
106→                <li>
107→                  <a href="/handbook">Handbook</a>
108→                </li>
109→                {breadcrumbs.map((crumb) => (
110→                  <li>
111→                    <span aria-hidden="true">›</span>
112→                    <a href={`/handbook/${crumb.id}`}>{crumb.data.title}</a>
113→                  </li>
114→                ))}
115→                <li aria-current="page">
116→                  <span aria-hidden="true">›</span>
117→                  <span>{page.data.title}</span>
118→                </li>
119→              </ol>
120→            </nav>
