 2→import { getCollection, render } from "astro:content";
 3→import BaseLayout from "@/layouts/base.astro";
 4→import { mdxComponents } from "@/components/mdx/components";
 5→
 6→export async function getStaticPaths() {
 7→  const pages = await getCollection("pages");
 8→
 9→  // Validate no slug collisions with reserved routes
10→  const reserved = ["blog", "projects", "labs", "handbook", "who-we-are", "what-we-do", "work-with-us"];
11→
12→  for (const page of pages) {
13→    const topSegment = page.id.split("/")[0];
14→    if (reserved.includes(topSegment)) {
15→      throw new Error(`Page "${page.id}" collides with reserved route /${topSegment}. Rename it.`);
16→    }
17→  }
18→
19→  return pages.map((page) => ({
20→    params: { slug: page.id },
21→    props: { page },
22→  }));
23→}
24→
25→const { page } = Astro.props;
26→const { Content } = await render(page);
27→
28→const seo = page.data.seo;
29→const title = seo?.metaTitle ?? page.data.title;
30→const description = seo?.metaDescription ?? `${page.data.title} — Significa`;
31→---
32→
33→<BaseLayout title={title} description={description} ogImage={seo?.ogImage}>
34→  <article>
35→    <h1>{page.data.title}</h1>
36→    <Content components={mdxComponents} />
37→  </article>
38→</BaseLayout>
39→

