 2→import type { APIContext } from "astro";
 3→import { getPosts } from "@/lib/collections";
 4→
 5→export async function GET(context: APIContext) {
 6→  const posts = await getPosts();
 7→
 8→  return rss({
 9→    title: "Significa Blog",
10→    description: "Thoughts on design, engineering, and building products.",
11→    site: context.site!.href,
12→    items: posts.map((post) => ({
13→      title: post.data.title,
14→      description: post.data.description,
15→      pubDate: post.data.date,
16→      link: `/blog/${post.id}`,
17→    })),
18→  });
19→}
