152→export async function getHandbookBreadcrumbs(entry: HandbookEntry) {
153→  const parts = entry.id.split("/");
154→  if (parts.length < 2) return [];
155→
156→  const pages = await getHandbookPages();
157→  const breadcrumbs: HandbookEntry[] = [];
158→
159→  for (let i = 1; i < parts.length; i++) {
160→    const ancestorId = parts.slice(0, i).join("/");
161→    const ancestor = pages.find((p) => p.id === ancestorId);
162→    if (ancestor) breadcrumbs.push(ancestor);
163→  }
