---
interface Props {
  title: string;
  author?: string;
  role?: string;
  tags?: string[];
  bg?: string;
  href?: string;
}

const {
  title,
  author,
  role,
  tags,
  bg = "var(--beige-50)",
  href,
} = Astro.props;

const Tag = href ? "a" : "div";
---

<article class="blog-card">
  <Tag class="card-inner" {...(href ? { href } : {})}>
    <div class="card-media" style={`--media-bg: ${bg};`}></div>
    <div class="card-body">
      <h3 class="card-title">{title}</h3>
      {
        (author || role) && (
          <p class="card-author">
            {author}
            {role && <span class="card-role">{role}</span>}
          </p>
        )
      }
      {
        tags && tags.length > 0 && (
          <ul class="card-tags">
            {tags.map((tag) => (
              <li class="card-tag">{tag}</li>
            ))}
          </ul>
        )
      }
    </div>
  </Tag>
</article>

<style>
  .blog-card {
    border-radius: 8px;
    overflow: hidden;
    background-color: var(--color-surface);
  }

  .card-inner {
    display: flex;
    flex-direction: column;
    width: 100%;
    height: 100%;
    text-decoration: none;
    color: var(--color-text);
    transition: opacity var(--duration-fast) var(--ease-out);
  }

  a.card-inner:hover {
    opacity: 0.9;
    color: var(--color-text);
  }

  .card-media {
    flex-shrink: 0;
    aspect-ratio: 368 / 338;
    background-color: var(--media-bg);
    border-radius: 8px;
  }

  .card-body {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    padding: 1rem 0;
  }

  .card-title {
    font-family: var(--font-display);
    font-size: var(--text-lg);
    font-weight: var(--weight-bold);
    line-height: var(--leading-tight);
    margin: 0;
  }

  .card-author {
    font-size: var(--text-sm);
    color: var(--color-text-muted);
    margin: 0;
  }

  .card-role {
    display: inline;
  }

  .card-role::before {
    content: " \00B7 ";
  }

  .card-tags {
    display: flex;
    flex-wrap: wrap;
    gap: 0.5rem;
    list-style: none;
    margin: 0.25rem 0 0;
    padding: 0;
  }

  .card-tag {
    font-size: var(--text-sm);
    color: var(--color-text-muted);
    padding: 0.125rem 0.5rem;
    border: 1px solid var(--color-border);
    border-radius: 2rem;
  }
</style>

