import BlogCard from "@/components/blog-card.astro";
import MosaicIcon from "@/components/mosaic-icon.astro";
import { getResolvedHighlights } from "@/lib/collections";

const highlights = await getResolvedHighlights();

const collectionPathMap: Record<string, string> = {
  projects: "/projects",
  blog: "/blog",
  playground: "/playground",
};

function estimateReadingTime(body: string | undefined): string {
  if (!body) return "1 min";
  const words = body.trim().split(/\s+/).length;
  const mins = Math.max(1, Math.round(words / 200));
  return `${mins} min`;
}

const highlightRows = highlights.map((h) => {
  const entry = h.entry;
  const basePath = collectionPathMap[h.collection] ?? "";
  return {
    label: h.label,
    title: entry?.data.title ?? "Untitled",
    href: entry ? `${basePath}/${entry.id}` : "#",
    readingTime: estimateReadingTime((entry as { body?: string })?.body),
  };
});

const projectMetrics = [
  { value: "59%", label: "Conversion rate", trend: "up" as const },
  { value: "12%", label: "Avg. order", trend: "up" as const },
  { value: "34%", label: "Orders", trend: "up" as const },
];

const awards = [
  { award: "Red Dot", year: 2025, project: "mishmash" },
  { award: "Ecommerce Awards", year: 2025, project: "Hey Harper" },
  { award: "Awwwards SOTD", year: 2025, project: "mishmash" },
  { award: "European Design Awards", year: 2025, project: "mishmash" },
  { award: "IF Design Award", year: 2024, project: "mishmash" },
  { award: "German Design Award", year: 2024, project: "mishmash" },
  { award: "European Design Awards", year: 2024, project: "Passaporte Natura" },
  { award: "Awwwards SOTD", year: 2024, project: "Dia" },
  { award: "German Design Award", year: 2024, project: "Zoko" },
  { award: "Red Dot", year: 2024, project: "Zoko" },
];

const designServices = [
  { label: "User Experience Design" },
  { label: "Interface Design" },
  { label: "Interaction Design" },
  { label: "Icon Design" },
  { label: "Product Strategy" },
  { label: "Conversion Optimisation" },
  { label: "Prototyping & Testing" },
  { label: "Design Systems" },
  { label: "Branding" },
];

const devServices = [
  { label: "React & Next.js" },
  { label: "Swift/iOS" },
  { label: "Kotlin/Android" },
  { label: "Node.js & APIs" },
  { label: "Cloud & DevOps" },
  { label: "QA & Testing" },
  { label: "Analytics" },
];

const blogPosts = [
  { title: "How we built a design system in 3 weeks", author: "Ryan Ziegler", role: "CEO of Certainty Software", tags: ["Design", "Code"] },
  { title: "The future of e-commerce design", author: "Ryan Ziegler", role: "CEO of Certainty Software", tags: ["Design", "Code"] },
  { title: "Why we switched to Astro", author: "Ryan Ziegler", role: "CEO of Certainty Software", tags: ["Design", "Code"] },
  { title: "Building accessible interfaces", author: "Ryan Ziegler", role: "CEO of Certainty Software", tags: ["Design", "Code"] },
];
