---
/**
 * Mosaic Icon
 *
 * Renders an icon from the mosaic grid system. Each cell contains ONE Significa
 * oval ("egg"). Inactive cells show an xs-sized muted dot. Active cells show
 * a larger egg in currentColor.
 *
 * State transitions driven by parent via CSS custom properties:
 *   --mosaic-state: 0 (idle) | 1 (active)
 *   --mosaic-duration: transition duration override
 *   --mosaic-ease: easing override
 */
import { mosaicIcons, MOSAIC_SCALES, type MosaicIconName } from "@/lib/mosaic-icons";

interface Props {
  name: MosaicIconName;
  class?: string;
}

const { name, class: className } = Astro.props;
const icon = mosaicIcons[name];

const cells = icon.idle.map((idleLevel, i) => {
  const hoverLevel = icon.hover?.[i] ?? idleLevel;
  return {
    idle: MOSAIC_SCALES[idleLevel],
    hover: MOSAIC_SCALES[hoverLevel],
  };
});

const EGG_PATH = "M1.73854 1.13073C1.73854 1.61081 1.34935 2 0.86927 2C0.389185 2 0 1.61081 0 1.13073C0 0.650646 0.389185 0 0.86927 0C1.34935 0 1.73854 0.650646 1.73854 1.13073Z";
---

<span
  class:list={["mosaic-icon", className]}
  style={`--cols:${icon.cols}`}
  aria-hidden="true"
>
  {cells.map((cell) => (
    <span class="mosaic-cell" style={`--i:${cell.idle};--h:${cell.hover}`}>
      <svg class="mosaic-egg" viewBox="0 0 1.73854 2">
        <path d={EGG_PATH} fill="currentColor" />
      </svg>
    </span>
  ))}
</span>

<style>
  .mosaic-icon {
    display: inline-grid;
    grid-template-columns: repeat(var(--cols), 1fr);
    grid-auto-rows: 1fr;
    width: calc(var(--cols) * 2px);
    aspect-ratio: 1;
    flex-shrink: 0;
  }

  .mosaic-cell {
    position: relative;
    aspect-ratio: 1;
  }

  .mosaic-egg {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    display: block;
    overflow: visible;

    --s: calc(var(--i) + (var(--h) - var(--i)) * var(--mosaic-state, 0));

    /* Always render at least xs size so every cell has a visible dot */
    --visual-s: max(0.275, var(--s));
    width: calc(100% * var(--visual-s));
    height: calc(100% * var(--visual-s));

    /* 1 when active (s > 0), 0 when background */
    --active: clamp(0, var(--s) * 10000, 1);

    /* Muted when inactive, full when active */
    opacity: calc(0.2 + var(--active) * 0.8);

    transition:
      width var(--mosaic-duration, var(--duration-fast)) var(--mosaic-ease, var(--ease-out)),
      height var(--mosaic-duration, var(--duration-fast)) var(--mosaic-ease, var(--ease-out)),
      opacity var(--mosaic-duration, var(--duration-fast)) var(--mosaic-ease, var(--ease-out));
  }
</style>

/**
 * Mosaic Icon System
 *
 * Icons are composed on a grid of cells (default 2px each). Each cell contains
 * an "egg" (the Significa oval) at one of 5 scale levels. The size gradient
 * across cells creates sub-pixel anti-aliasing.
 *
 * Icons can define two states (idle/hover) with different grid layouts.
 * Transitions between states are driven by the parent via CSS custom properties:
 *   --mosaic-state: 0 (idle, default) | 1 (active/hover)
 *   --mosaic-duration: transition duration (default: --duration-fast)
 *   --mosaic-ease: easing function (default: --ease-out)
 *
 * Color inherits via currentColor from the parent context.
 */

export type MosaicLevel = 0 | 1 | 2 | 3 | 4;

export interface MosaicIconDef {
  /** Number of columns in the grid */
  cols: number;
  /** Default state grid (flat array of size levels) */
  idle: MosaicLevel[];
  /** Optional hover/active state grid */
  hover?: MosaicLevel[];
}

/**
 * Scale factor for each size level (fraction of cell size).
 * 0 = invisible, 1(xs) = 27.5%, 2(s) = 57.5%, 3(m) = 87.5%, 4(l) = 100%
 */
export const MOSAIC_SCALES: readonly number[] = [0, 0.275, 0.575, 0.875, 1];

/* prettier-ignore */
export const mosaicIcons = {
  arrow: {
    cols: 7,
    idle: [
      0, 0, 2, 0, 0, 0, 0,
      0, 0, 3, 3, 0, 0, 0,
      2, 3, 3, 4, 4, 0, 0,
      2, 3, 3, 4, 4, 4, 0,
      2, 3, 3, 4, 4, 0, 0,
      0, 0, 0, 3, 3, 0, 0,
      0, 0, 0, 2, 0, 0, 0,
    ],
    hover: [
      0, 0, 0, 2, 0, 0, 0,
      0, 0, 0, 3, 3, 0, 0,
      1, 2, 3, 3, 4, 4, 0,
      1, 2, 3, 3, 4, 4, 4,
      1, 2, 3, 3, 4, 4, 0,
      0, 0, 0, 0, 3, 3, 0,
      0, 0, 0, 0, 2, 0, 0,
    ],
  },
} as const satisfies Record<string, MosaicIconDef>;

export type MosaicIconName = keyof typeof mosaicIcons;

