            <p class="awards-card-subtitle">We've earned 20+ awards</p>
          </div>
          <div class="awards-card-list">
            {awards.map((a) => (
              <AwardRow award={a.award} year={a.year} project={a.project} />
            ))}
          </div>
        </div>
      </div>
    </section>

    <!-- 5. Services -->
    <section class="services">
      <ServiceList
        title="Transforming insights into effective experiences."
        items={designServices}
      />
      <ServiceList
        title="Building in-house with precision and care."
        items={devServices}
      />
    </section>

