---
interface Props {
  title: string;
  subtitle?: string;
  bg?: string;
  fg?: string;
  size?: "large" | "small";
  href?: string;
}

const {
  title,
  subtitle,
  bg = "var(--beige-50)",
  fg = "var(--beige-950)",
  size = "large",
  href,
} = Astro.props;

const Tag = href ? "a" : "div";
---

<article class:list={["highlight-card", `highlight-card--${size}`]} style={`--card-bg: ${bg}; --card-fg: ${fg};`}>
  <Tag class="card-inner" {...(href ? { href } : {})}>
    <div class="card-content">
      {subtitle && <span class="card-subtitle">{subtitle}</span>}
      <h3 class="card-title">{title}</h3>
    </div>
  </Tag>
</article>

<style>
  .highlight-card {
    border-radius: 8px;
    overflow: hidden;
    width: 100%;
    height: 100%;
  }

  .card-inner {
    display: flex;
    flex-direction: column;
    justify-content: flex-end;
    width: 100%;
    height: 100%;
    min-height: 20rem;
    padding: 1.5rem;
    background-color: var(--card-bg);
    color: var(--card-fg);
    text-decoration: none;
    transition: opacity var(--duration-fast) var(--ease-out);
  }

  a.card-inner:hover {
    opacity: 0.9;
    color: var(--card-fg);
  }

  .card-content {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
  }

  .card-subtitle {
    font-size: var(--text-sm);
    opacity: 0.7;
  }

  .highlight-card--large .card-title {
    font-family: var(--font-display);
    font-size: var(--text-3xl);
    font-weight: var(--weight-bold);
    line-height: var(--leading-tight);
    margin: 0;
  }

  .highlight-card--small .card-title {
    font-family: var(--font-display);
    font-size: var(--text-2xl);
    font-weight: var(--weight-bold);
    line-height: var(--leading-tight);
    margin: 0;
  }

  .highlight-card--small .card-inner {
    min-height: 16rem;
  }
</style>

