    text-decoration: none;
    color: inherit;
    --mosaic-state: 0;
    transition: opacity var(--duration-fast) var(--ease-out);
  }

  .highlight-row:last-child {
    border-bottom: 0.5px solid var(--color-border-subtle);
  }

  .highlight-row:hover {
    --mosaic-state: 1;
  }

  .highlight-left {
    display: flex;
    align-items: center;
    gap: 1rem;
    min-width: 0;
  }

  .highlight-label {
    font-size: var(--text-sm);
    color: var(--color-text-muted);
    white-space: nowrap;
    flex-shrink: 0;
  }

  .highlight-title {
    font-size: var(--text-sm);
    font-weight: var(--weight-medium);
    color: var(--color-text);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .highlight-right {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    flex-shrink: 0;
  }

  .highlight-time {
    font-size: var(--text-sm);
    color: var(--color-text-muted);
  }

  /* ============================================================
     2. Showreel
     ============================================================ */
  .showreel {
    min-height: 560px;
    background: var(--beige-100);
    border-radius: 8px;
  }

  /* ============================================================
     3. Intro
     ============================================================ */
  .intro {
    padding: 200px 0 100px;
  }

  .intro-inner {
    max-width: 500px;
    margin: 0 auto;
    text-align: center;
  }

  .intro-title {
    font-size: var(--text-2xl);
    font-weight: var(--weight-medium);
    line-height: var(--leading-tight);
    color: var(--color-text);
    margin: 0 0 1.5rem;
  }

  .intro-body {
    font-size: var(--text-lg);
    font-weight: var(--weight-normal);
    line-height: var(--leading-normal);
    color: var(--color-text-muted);
    margin: 0;
  }

  /* ============================================================
     4. Prizes (2x2 grid)
     ============================================================ */
  .prizes-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 8px;
  }

