      min-height: calc(100svh - 6rem);
      padding: 1.5rem;
    }

    .highlight-title {
      font-size: 0.75rem;
    }

    .intro {
      padding: 100px 1rem 60px;
    }

    .services {
      padding: 3rem 1rem;
      gap: 3rem;
    }
  }
</style>

