---
import MosaicIcon from "@/components/mosaic-icon.astro";

interface Props {
  title: string;
  readTime: string;
  href?: string;
  active?: boolean;
}

const { title, readTime, href, active = false } = Astro.props;
const Tag = href ? "a" : "article";
---

<Tag
  class:list={["highlight-row", { "is-active": active }]}
  {...(href ? { href } : {})}
>
  <div class="badge">
    <MosaicIcon name="bag" size={12} />
  </div>
  <p class="title">{title}</p>
  <div class="meta">
    <span class="read-time">{readTime}</span>
    <MosaicIcon name="arrow" size={14} />
  </div>
</Tag>

<style>
  .highlight-row {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 1.375rem 1rem;
    width: 100%;
    border-top: 0.5px solid var(--color-border-subtle);
    text-decoration: none;
    background: var(--color-surface);
    color: var(--color-text-muted);
    --mosaic-state: 0;
    transition:
      background var(--duration-fast) var(--ease-out),
      color var(--duration-fast) var(--ease-out);
  }

  a.highlight-row {
    cursor: pointer;
  }

  .highlight-row:hover,
  .highlight-row.is-active {
    background: var(--color-surface-hover);
    color: var(--color-text);
    --mosaic-state: 1;
  }

  .highlight-row:focus-visible {
    outline: 2px solid var(--color-primary);
    outline-offset: -2px;
  }

  .badge {
    width: 1.25rem;
    height: 1.25rem;
    border-radius: var(--radius-sm);
    display: flex;
    align-items: center;
    justify-content: center;
    overflow: hidden;
    flex-shrink: 0;
    background: var(--color-icon-muted);
    transition: background var(--duration-fast) var(--ease-out);
  }

  .highlight-row:hover .badge,
  .highlight-row.is-active .badge {
    background: var(--color-text);
    color: var(--color-surface);
  }

  .title {
    font-family: var(--font-display);
    font-size: var(--text-sm);
    font-weight: var(--weight-medium);
    text-transform: uppercase;
    letter-spacing: 0.04em;
    line-height: var(--leading-tight);
    flex: 1;
    margin: 0;
  }

  .read-time {
    font-family: var(--font-display);
    font-size: var(--text-xs);
    font-weight: var(--weight-medium);
    text-transform: uppercase;
    letter-spacing: 0.05em;
    white-space: nowrap;
  }

  .meta {
    display: flex;
    align-items: center;
    gap: 1rem;
    flex-shrink: 0;
  }

  @media (prefers-reduced-motion: reduce) {
    .highlight-row,
    .badge {
      transition: none;
    }
  }
</style>

