const highlights = await getResolvedHighlights();

const collectionPathMap: Record<string, string> = {
  projects: "/projects",
  blog: "/blog",
  playground: "/playground",
};

function estimateReadingTime(body: string | undefined): string {
  if (!body) return "1 min";
  const words = body.trim().split(/\s+/).length;
  const mins = Math.max(1, Math.round(words / 200));
  return `${mins} min`;
}

const highlightRows = highlights.map((h) => {
  const entry = h.entry;
  const basePath = collectionPathMap[h.collection] ?? "";
  return {
    label: h.label,
    title: entry?.data.title ?? "Untitled",
    href: entry ? `${basePath}/${entry.id}` : "#",
