  title="Significa — Design and Development Agency"
  description="We are a design and development agency building digital products that work beautifully. From strategy to code, we deliver user-centred platforms for ambitious businesses."
>
  <div class="page">
    <!-- TEMP: HighlightRow test -->
    <div style="max-width:800px; margin:40px auto; border: 0.5px solid var(--color-border-subtle); border-radius: var(--radius-md); overflow:hidden;">
      <HighlightRow title="E-commerce strategies that helps shine and convert" readTime="5 MIN" active />
      <HighlightRow title="Impactful design systems that scale and grow" readTime="10 MIN" />
      <HighlightRow title="Tech solutions that drive results" readTime="2 MIN" />
      <HighlightRow title="Design is the invisible language between humans and the rest." readTime="6 MIN" />
    </div>
    <!-- 1. Hero -->
    <section class="hero">
      <div class="hero-top">
        <h1 class="hero-title">Significa®</h1>
        <p class="hero-subtitle">Mean something.</p>
      </div>
      <nav class="hero-highlights" aria-label="Featured content">
        {highlightRows.map((row) => (
          <a class="highlight-row" href={row.href}>
            <span class="highlight-left">
              <span class="highlight-label">{row.label}</span>
              <span class="highlight-title">{row.title}</span>
            </span>
            <span class="highlight-right">
              <span class="highlight-time">{row.readingTime}</span>
              <MosaicIcon name="arrow" />
            </span>
          </a>
        ))}
      </nav>
    </section>

    <!-- 2. Showreel -->
    <section class="showreel"></section>

    <!-- 3. Intro -->
    <section class="intro">
      <div class="intro-inner">
        <h2 class="intro-title">From strategy to code, we deliver user-centred platforms for ambitious businesses.</h2>
        <p class="intro-body">Whether it's an e-commerce shop, a mobile app, a ticketing platform, or a design system, we'll build it with care and curiosity, backed by +10 years of expertise, recognised by +20 international awards.</p>
      </div>
    </section>

    <!-- 4. Prizes (2x2 grid) -->
    <section class="prizes">
      <div class="prizes-grid">
        <ProjectCard
          title="mishmash"
          metrics={projectMetrics}
          bg="var(--beige-50)"
          fg="var(--beige-950)"
        />
        <ProjectCard
          title="Hey Harper"
          metrics={projectMetrics}
          bg="var(--beige-50)"
          fg="var(--beige-950)"
        />
        <ProjectCard
          title="Dia"
          metrics={projectMetrics}
          bg="var(--beige-50)"
          fg="var(--beige-950)"
        />
        <div class="awards-card">
          <div class="awards-card-header">
            <h3 class="awards-card-title">International recognition.</h3>
            <p class="awards-card-subtitle">We've earned 20+ awards</p>
          </div>
          <div class="awards-card-list">
            {awards.map((a) => (
              <AwardRow award={a.award} year={a.year} project={a.project} />
            ))}
          </div>
        </div>
      </div>
    </section>

    <!-- 5. Services -->
    <section class="services">
      <ServiceList
        title="Transforming insights into effective experiences."
        items={designServices}
      />
      <ServiceList
        title="Building in-house with precision and care."
        items={devServices}
      />
    </section>

    <!-- 6. Highlights -->
    <section class="highlights">
      <div class="highlights-grid">
        <div class="highlights-large">
          <HighlightCard
            title="You'll enjoy our process as much as you enjoy your product. Free promise."
            size="large"
            bg="var(--beige-50)"
          />
        </div>
        <div class="highlights-small">
          <HighlightCard
            title="Bring your specs to Significa but give them the creative freedom to unleash the best possible design and solution for your needs."
            subtitle="84.7% Customer experience score"
            size="small"
            bg="var(--beige-100)"
          />
        </div>
      </div>
    </section>

    <!-- 7. Blog -->
    <section class="blog">
      <div class="blog-grid">
        {blogPosts.map((post) => (
          <BlogCard
            title={post.title}
            author={post.author}
            role={post.role}
            tags={post.tags}
          />
        ))}
      </div>
    </section>
  </div>
</BaseLayout>

<style>
  /* ============================================================
     Page container
     ============================================================ */
  .page {
    max-width: 1512px;
    margin: 0 auto;
    padding: 0.5rem 0.5rem 0;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
  }

  /* ============================================================
     1. Hero
     ============================================================ */
  .hero {
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    min-height: calc(100svh - 7.5rem);
    background: var(--color-surface);
    border: 0.5px solid var(--color-border-subtle);
    border-radius: 0.75rem;
    padding: 2rem;
  }

  .hero-top {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
  }

  .hero-title {
    font-family: var(--font-display);
    font-size: var(--text-4xl);
    font-weight: var(--weight-bold);
    line-height: var(--leading-tight);
    color: var(--color-text);
    margin: 0;
  }

  .hero-subtitle {
    font-family: var(--font-display);
    font-size: var(--text-4xl);
    font-weight: var(--weight-normal);
    line-height: var(--leading-tight);
    color: var(--color-text);
    margin: 0;
  }

  .hero-highlights {
    display: flex;
    flex-direction: column;
  }

  .highlight-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 1rem;
    padding: 0.75rem 0;
    border-top: 0.5px solid var(--color-border-subtle);
    text-decoration: none;
    color: inherit;
    --mosaic-state: 0;
    transition: opacity var(--duration-fast) var(--ease-out);
  }

  .highlight-row:last-child {
    border-bottom: 0.5px solid var(--color-border-subtle);
  }

  .highlight-row:hover {
    --mosaic-state: 1;
  }

  .highlight-left {
    display: flex;
    align-items: center;
    gap: 1rem;
    min-width: 0;
  }

  .highlight-label {
    font-size: var(--text-sm);
    color: var(--color-text-muted);
    white-space: nowrap;
    flex-shrink: 0;
  }

  .highlight-title {
    font-size: var(--text-sm);
    font-weight: var(--weight-medium);
    color: var(--color-text);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .highlight-right {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    flex-shrink: 0;
  }

  .highlight-time {
    font-size: var(--text-sm);
    color: var(--color-text-muted);
  }

  /* ============================================================
     2. Showreel
     ============================================================ */
  .showreel {
    min-height: 560px;
    background: var(--beige-100);
    border-radius: 8px;
  }

  /* ============================================================
     3. Intro
     ============================================================ */
  .intro {
    padding: 200px 0 100px;
  }

  .intro-inner {
    max-width: 500px;
    margin: 0 auto;
    text-align: center;
  }

  .intro-title {
    font-size: var(--text-2xl);
    font-weight: var(--weight-medium);
    line-height: var(--leading-tight);
    color: var(--color-text);
    margin: 0 0 1.5rem;
  }

  .intro-body {
    font-size: var(--text-lg);
    font-weight: var(--weight-normal);
    line-height: var(--leading-normal);
    color: var(--color-text-muted);
    margin: 0;
  }

  /* ============================================================
     4. Prizes (2x2 grid)
     ============================================================ */
  .prizes-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 8px;
  }

  .awards-card {
    aspect-ratio: 1 / 1;
    border-radius: 8px;
    overflow: hidden;
    background: var(--beige-50);
    color: var(--beige-950);
    display: flex;
    flex-direction: column;
  }

  .awards-card-header {
    padding: 16px;
    flex-shrink: 0;
  }

  .awards-card-title {
    font-family: var(--font-display);
    font-size: var(--text-2xl);
    font-weight: var(--weight-bold);
    line-height: var(--leading-tight);
    margin: 0 0 0.25rem;
  }

  .awards-card-subtitle {
    font-family: var(--font-display);
    font-size: var(--text-base);
    font-weight: var(--weight-normal);
    opacity: 0.7;
    margin: 0;
  }

  .awards-card-list {
    flex: 1;
    overflow-y: auto;
  }

  /* ============================================================
     5. Services
     ============================================================ */
  .services {
    display: flex;
    flex-direction: column;
    gap: 6rem;
    padding: 8rem 2rem;
    max-width: var(--max-width);
    margin: 0 auto;
    width: 100%;
    box-sizing: border-box;
  }

  /* ============================================================
     6. Highlights
     ============================================================ */
  .highlights-grid {
    display: grid;
    grid-template-columns: 2fr 1fr;
    gap: 8px;
  }

  .highlights-large,
  .highlights-small {
    min-height: 20rem;
  }

  /* ============================================================
     7. Blog
     ============================================================ */
  .blog-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 8px;
  }

  /* ============================================================
     Responsive
     ============================================================ */
  @media (max-width: 1024px) {
    .prizes-grid {
      grid-template-columns: 1fr;
    }

    .highlights-grid {
      grid-template-columns: 1fr;
    }

    .blog-grid {
      grid-template-columns: repeat(2, 1fr);
    }

    .services {
      padding: 4rem 1.5rem;
      gap: 4rem;
    }
  }

  @media (max-width: 640px) {
    .blog-grid {
      grid-template-columns: 1fr;
    }

    .hero {
      min-height: calc(100svh - 6rem);
      padding: 1.5rem;
    }

    .highlight-title {
      font-size: 0.75rem;
    }

    .intro {
      padding: 100px 1rem 60px;
    }

    .services {
      padding: 3rem 1rem;
      gap: 3rem;
    }
  }
</style>

---
import BaseLayout from "@/layouts/base.astro";
import ProjectCard from "@/components/project-card.astro";
import AwardRow from "@/components/award-row.astro";
import ServiceList from "@/components/service-list.astro";
import HighlightCard from "@/components/highlight-card.astro";
import BlogCard from "@/components/blog-card.astro";
import MosaicIcon from "@/components/mosaic-icon.astro";
import { getResolvedHighlights } from "@/lib/collections";

const highlights = await getResolvedHighlights();

const collectionPathMap: Record<string, string> = {
  projects: "/projects",
  blog: "/blog",
  playground: "/playground",
};

function estimateReadingTime(body: string | undefined): string {
  if (!body) return "1 min";
  const words = body.trim().split(/\s+/).length;
  const mins = Math.max(1, Math.round(words / 200));
  return `${mins} min`;
}

const highlightRows = highlights.map((h) => {
  const entry = h.entry;
  const basePath = collectionPathMap[h.collection] ?? "";
  return {
    label: h.label,
    title: entry?.data.title ?? "Untitled",
    href: entry ? `${basePath}/${entry.id}` : "#",
    readingTime: estimateReadingTime((entry as { body?: string })?.body),
  };
});

const projectMetrics = [
  { value: "59%", label: "Conversion rate", trend: "up" as const },
  { value: "12%", label: "Avg. order", trend: "up" as const },
  { value: "34%", label: "Orders", trend: "up" as const },
];

const awards = [
  { award: "Red Dot", year: 2025, project: "mishmash" },
  { award: "Ecommerce Awards", year: 2025, project: "Hey Harper" },
  { award: "Awwwards SOTD", year: 2025, project: "mishmash" },
  { award: "European Design Awards", year: 2025, project: "mishmash" },
  { award: "IF Design Award", year: 2024, project: "mishmash" },
  { award: "German Design Award", year: 2024, project: "mishmash" },
  { award: "European Design Awards", year: 2024, project: "Passaporte Natura" },
  { award: "Awwwards SOTD", year: 2024, project: "Dia" },
  { award: "German Design Award", year: 2024, project: "Zoko" },
  { award: "Red Dot", year: 2024, project: "Zoko" },
];

const designServices = [
  { label: "User Experience Design" },
  { label: "Interface Design" },
  { label: "Interaction Design" },
  { label: "Icon Design" },
  { label: "Product Strategy" },
  { label: "Conversion Optimisation" },
  { label: "Prototyping & Testing" },
  { label: "Design Systems" },
  { label: "Branding" },
];

const devServices = [
  { label: "React & Next.js" },
  { label: "Swift/iOS" },
  { label: "Kotlin/Android" },
  { label: "Node.js & APIs" },
  { label: "Cloud & DevOps" },
  { label: "QA & Testing" },
  { label: "Analytics" },
];

const blogPosts = [
  { title: "How we built a design system in 3 weeks", author: "Ryan Ziegler", role: "CEO of Certainty Software", tags: ["Design", "Code"] },
  { title: "The future of e-commerce design", author: "Ryan Ziegler", role: "CEO of Certainty Software", tags: ["Design", "Code"] },
  { title: "Why we switched to Astro", author: "Ryan Ziegler", role: "CEO of Certainty Software", tags: ["Design", "Code"] },
  { title: "Building accessible interfaces", author: "Ryan Ziegler", role: "CEO of Certainty Software", tags: ["Design", "Code"] },
];
